import { WithConditionals } from '@/checkout/components/ConditionalWrapper/ConditionalWrapper';
import '@/checkout/components/PaymentOnAccount/PaymentOnAccount.css';
import { PaymentOnAccountSkeleton } from '@/checkout/components/PaymentOnAccount/PaymentOnAccountSkeleton';
import { Money } from '@/checkout/data/models';
import {
  Field,
  InLineAlert,
  Input,
  Price,
} from '@adobe-commerce/elsie/components';
import { Text, useText } from '@adobe-commerce/elsie/i18n';
import { classes, getPriceFormatter } from '@adobe-commerce/elsie/lib';
import { FunctionComponent } from 'preact';
import { HTMLAttributes } from 'preact/compat';

export type CompanyCredit = {
  availableCredit: Money;
  exceedLimit?: boolean;
};

export interface PaymentOnAccountProps extends HTMLAttributes<HTMLFormElement> {
  referenceNumber?: string;
  onReferenceNumberChange?: (event: Event) => void;
  onReferenceNumberBlur?: (event: Event) => void;
  companyCredit?: CompanyCredit | null;
  totalAmount?: Money | null;
}

const calculateExceededAmount = (
  companyCredit: CompanyCredit | null,
  totalAmount: Money | null
): Money | null => {
  if (!companyCredit?.availableCredit || !totalAmount) return null;

  const availableValue = companyCredit.availableCredit.value;
  const cartValue = totalAmount.value;
  const exceededValue = cartValue - availableValue;

  if (exceededValue <= 0) return null;

  return {
    value: exceededValue,
    currency: companyCredit.availableCredit.currency,
  };
};

const PaymentOnAccountComponent: FunctionComponent<PaymentOnAccountProps> = ({
  className,
  referenceNumber = '',
  onReferenceNumberChange,
  onReferenceNumberBlur,
  companyCredit = null,
  totalAmount = null,
  ...props
}) => {
  const exceededAmount = calculateExceededAmount(companyCredit, totalAmount);
  const creditLimit = companyCredit?.availableCredit;

  const priceFormatter = getPriceFormatter({
    currency: totalAmount?.currency ?? '',
  });

  const translations = useText({
    referenceNumberLabel: 'Checkout.PaymentOnAccount.referenceNumberLabel',
    referenceNumberPlaceholder:
      'Checkout.PaymentOnAccount.referenceNumberPlaceholder',
    referenceNumberHint: 'Checkout.PaymentOnAccount.referenceNumberHint',
    availableCreditLabel: 'Checkout.PaymentOnAccount.availableCreditLabel',
    exceedLimitError: 'Checkout.PaymentOnAccount.exceedLimitError',
    exceedLimitWarning: (exceededAmount ? (
      <Text
        fields={{
          creditLimit: priceFormatter.format(creditLimit?.value ?? 0),
          exceededAmount: priceFormatter.format(exceededAmount?.value ?? 0),
        }}
        id="Checkout.PaymentOnAccount.exceedLimitWarning"
      />
    ) : (
      ''
    )) as any,
  });

  return (
    <div
      className="checkout-payment-on-account"
      data-testid="checkout-payment-on-account"
    >
      <form
        {...props}
        noValidate
        className={classes(['checkout-payment-on-account__form', className])}
        data-testid="checkout-payment-on-account-form"
        name="checkout-payment-on-account__form"
      >
        {companyCredit && companyCredit.availableCredit && (
          <div
            className="checkout-payment-on-account__credit"
            data-testid="checkout-payment-on-account-credit"
          >
            <span className="checkout-payment-on-account__credit-label">
              {translations.availableCreditLabel}
            </span>
            <span className="checkout-payment-on-account__credit-amount">
              <Price
                amount={companyCredit?.availableCredit.value}
                currency={companyCredit?.availableCredit.currency}
              />
            </span>
          </div>
        )}

        <Field hint={translations.referenceNumberHint}>
          <Input
            aria-label={translations.referenceNumberLabel}
            floatingLabel={translations.referenceNumberLabel}
            id="reference-number"
            name="reference-number"
            placeholder={translations.referenceNumberPlaceholder}
            type="text"
            value={referenceNumber}
            onBlur={onReferenceNumberBlur}
            onChange={onReferenceNumberChange}
          />
        </Field>

        {exceededAmount && (
          <div
            className="checkout-payment-on-account__exceed-message"
            data-testid="checkout-payment-on-account-exceed-message"
          >
            <InLineAlert
              heading={
                companyCredit?.exceedLimit
                  ? translations.exceedLimitWarning
                  : translations.exceedLimitError
              }
              type={companyCredit?.exceedLimit ? 'warning' : 'error'}
              variant="primary"
            />
          </div>
        )}
      </form>
    </div>
  );
};

export const PaymentOnAccount = WithConditionals(
  PaymentOnAccountComponent,
  PaymentOnAccountSkeleton
);
