import { WithConditionals } from '@/checkout/components/ConditionalWrapper';
import '@/checkout/components/EstimateShipping/EstimateShipping.css';
import { EstimateShippingSkeleton } from '@/checkout/components/EstimateShipping/EstimateShippingSkeleton';
import { useText } from '@adobe-commerce/elsie/i18n';
import { VComponent, classes } from '@adobe-commerce/elsie/lib';
import { FunctionComponent, VNode } from 'preact';
import { HTMLAttributes } from 'preact/compat';

export interface EstimateShippingProps {
  label: VNode<HTMLAttributes<HTMLSpanElement>>;
  price: VNode<HTMLAttributes<HTMLSpanElement>>;
  priceExclTax?: VNode<HTMLAttributes<HTMLSpanElement>>;
  taxExcluded?: boolean;
  taxIncluded?: boolean;
}

const EstimateShippingComponent: FunctionComponent<EstimateShippingProps> = ({
  label,
  price,
  priceExclTax,
  taxExcluded = false,
  taxIncluded = false,
}) => {
  const translations = useText({
    withTaxes: 'Checkout.EstimateShipping.withTaxes',
    withoutTaxes: 'Checkout.EstimateShipping.withoutTaxes',
  });

  return (
    <div className="checkout-estimate-shipping" data-testid="estimate-shipping">
      <VComponent className="checkout-estimate-shipping__label" node={label} />
      <VComponent className="checkout-estimate-shipping__price" node={price} />

      {taxIncluded && (
        <span
          className={classes(['checkout-estimate-shipping__caption'])}
          data-testid="shipping-tax-included"
        >
          {translations.withTaxes}
        </span>
      )}

      {taxExcluded && (
        <span
          className={classes(['checkout-estimate-shipping__caption'])}
          data-testid="shipping-tax-included-excluded"
        >
          {priceExclTax}&nbsp;
          {translations.withoutTaxes}
        </span>
      )}
    </div>
  );
};

export const EstimateShipping = WithConditionals(
  EstimateShippingComponent,
  EstimateShippingSkeleton
);
