import '@/checkout/components/ServerError/ServerError.css';
import {
  Button,
  Icon,
  IllustratedMessage,
} from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { OrderError } from '@adobe-commerce/elsie/icons';
import { classes } from '@adobe-commerce/elsie/lib';
import { FunctionComponent, RefObject } from 'preact';
import { HTMLAttributes } from 'preact/compat';

export interface ServerErrorProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'icon'> {
  errorMessageRef?: RefObject<HTMLParagraphElement>;
  errorMessage: string;
  contactSupport?: string;
  onClick?: (e: any) => void;
}

export const ServerError: FunctionComponent<ServerErrorProps> = ({
  className,
  contactSupport,
  errorMessage,
  onClick,
  errorMessageRef,
}) => {
  const translations = useText({
    Title: 'Checkout.ServerError.title',
    Message: 'Checkout.ServerError.message',
    ContactSupport: 'Checkout.ServerError.contactSupport',
    Button: 'Checkout.ServerError.button',
  });

  const heading = errorMessage !== '' ? errorMessage : translations.Title;

  return (
    <IllustratedMessage
      action={
        <Button
          className={classes(['checkout-server-error__button'])}
          name="server-error-button"
          onClick={onClick}
        >
          {translations.Button}
        </Button>
      }
      aria-describedby="checkout-server-error__message"
      aria-invalid="true"
      aria-live="polite"
      className={classes(['checkout-server-error', className])}
      data-testid="checkout-server-error"
      heading={heading}
      icon={
        <Icon
          className={classes(['checkout-server-error__icon'])}
          source={OrderError}
        />
      }
      message={
        <p
          ref={errorMessageRef}
          data-testid="checkout-server-error-message"
          id={classes(['checkout-server-error__message'])}
        >
          {translations.Message}
          <br />
          <span>{contactSupport ?? translations.ContactSupport}</span>
        </p>
      }
    />
  );
};
