import '@/checkout/components/PurchaseOrder/PurchaseOrder.css';
import { htmlPatterns } from '@/checkout/lib/validation';
import { Field, Input } from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { classes } from '@adobe-commerce/elsie/lib';
import { FunctionComponent } from 'preact';
import { HTMLAttributes } from 'preact/compat';

export interface PurchaseOrderProps extends HTMLAttributes<HTMLFormElement> {
  error?: string;
  referenceNumber?: string;
  onReferenceNumberBlur?: (event: Event) => void;
  onReferenceNumberChange?: (event: Event) => void;
  onInvalidReferenceNumber?: (event: Event) => void;
}

export const PurchaseOrder: FunctionComponent<PurchaseOrderProps> = ({
  className,
  error = '',
  referenceNumber = '',
  onReferenceNumberBlur,
  onReferenceNumberChange,
  onInvalidReferenceNumber,
  ...props
}) => {
  const translations = useText({
    refNumberHint: 'Checkout.PurchaseOrder.referenceNumberHint',
    refNumberLabel: 'Checkout.PurchaseOrder.referenceNumberLabel',
    refNumberPlaceholder: 'Checkout.PurchaseOrder.referenceNumberPlaceholder',
  });

  return (
    <div
      className="checkout-purchase-order"
      data-testid="checkout-purchase-order"
    >
      <form
        {...props}
        noValidate
        className={classes(['checkout-purchase-order__form', className])}
        data-testid="checkout-purchase-order-form"
      >
        <Field error={error} hint={translations.refNumberHint || undefined}>
          <Input
            aria-required="true"
            floatingLabel={`${translations.refNumberLabel} *`}
            id="reference-number"
            name="reference-number"
            pattern={htmlPatterns.NOT_EMPTY}
            placeholder={translations.refNumberPlaceholder}
            required={true}
            type="text"
            value={referenceNumber}
            onBlur={onReferenceNumberBlur}
            onChange={onReferenceNumberChange}
            onInvalid={onInvalidReferenceNumber}
          />
        </Field>
      </form>
    </div>
  );
};
