import '@/checkout/components/AddressValidation/AddressValidation.css';
import { AddressInput } from '@/checkout/data/models';
import { classes } from '@adobe-commerce/elsie/lib';
import { useText } from '@adobe-commerce/elsie/i18n';
import { FunctionComponent } from 'preact';
import { HTMLAttributes } from 'preact/compat';
import { Header, ToggleButton } from '@adobe-commerce/elsie/components';

export interface AddressValidationProps extends HTMLAttributes<HTMLDivElement> {
  busy?: boolean;
  currentAddress: AddressInput | null | undefined;
  selection: 'suggested' | 'original' | null;
  suggestedAddress: AddressInput | null;
  onSelectionChange: (selection: 'suggested' | 'original') => void;
}

export function formatAddressLine(
  address: AddressInput | null | undefined
): string[] {
  if (!address) return [];
  const name = `${address.firstName} ${address.lastName}`.trim();
  const street = address.street?.[0] ?? '';
  const city = address.city ?? '';
  const region = address.region || '';
  const post = address.postcode ?? '';
  const country = address.countryCode ?? '';

  let cityRegion = '';
  if (city && region) {
    cityRegion = `${city}, ${region}`;
  } else if (city) {
    cityRegion = city;
  } else if (region) {
    cityRegion = region;
  }

  let cityRegionPost = cityRegion;
  if (post) {
    cityRegionPost = cityRegion ? `${cityRegion} ${post}` : post;
  }

  let line3 = cityRegionPost;
  if (country) {
    line3 = cityRegionPost ? `${cityRegionPost}, ${country}` : country;
  }

  return [name, street, line3];
}

const AddressBlock: FunctionComponent<{
  title: string;
  address: AddressInput | null | undefined;
  selected: boolean;
  busy?: boolean;
  onChange: () => void;
}> = ({ title, address, selected, busy, onChange }) => {
  const [line1, line2, line3] = formatAddressLine(address);
  const label = (
    <div>
      <div className="checkout-address-validation__option-title">
        <strong>{title}</strong>
      </div>
      {line1 && <div>{line1}</div>}
      {line2 && <div>{line2}</div>}
      {line3 && <div>{line3}</div>}
    </div>
  );
  return (
    <div className="checkout-address-validation__option">
      <ToggleButton
        busy={busy}
        className="checkout-address-validation__radio"
        label={label}
        name="address-validation-choice"
        selected={selected}
        value={title}
        onChange={onChange}
      />
    </div>
  );
};

export const AddressValidation: FunctionComponent<AddressValidationProps> = ({
  busy = false,
  className,
  currentAddress,
  onSelectionChange,
  selection,
  suggestedAddress,
}) => {
  const hasSuggestion = !!suggestedAddress;
  const translations = useText({
    title: 'Checkout.AddressValidation.title',
    subtitle: 'Checkout.AddressValidation.subtitle',
    suggestedAddress: 'Checkout.AddressValidation.suggestedAddress',
    originalAddress: 'Checkout.AddressValidation.originalAddress',
  });

  return (
    <div className={classes(['checkout-address-validation', className])}>
      <Header
        className="checkout-address-validation__title"
        divider={false}
        title={translations.title}
      />
      <div className="checkout-address-validation__subtitle">
        {translations.subtitle}
      </div>

      <div
        className={classes([
          'checkout-address-validation__options',
          busy && 'checkout-address-validation__options--busy',
        ])}
      >
        {hasSuggestion && (
          <AddressBlock
            address={suggestedAddress}
            busy={busy}
            selected={selection === 'suggested'}
            title={translations.suggestedAddress}
            onChange={() => onSelectionChange('suggested')}
          />
        )}

        <AddressBlock
          address={currentAddress}
          busy={busy}
          selected={selection === 'original'}
          title={translations.originalAddress}
          onChange={() => onSelectionChange('original')}
        />
      </div>
    </div>
  );
};
