import { WithConditionals } from '@/checkout/components/ConditionalWrapper/ConditionalWrapper';
import '@/checkout/components/ShippingMethods/ShippingMethods.css';
import { ShippingMethodsSkeleton } from '@/checkout/components/ShippingMethods/ShippingMethodsSkeleton';
import { ShippingMethod } from '@/checkout/data/models';
import { scrollToElement } from '@/checkout/lib/utils/dom';
import { UIComponentType } from '@/checkout/types';
import {
  Icon,
  IllustratedMessage,
  InLineAlert,
  Price,
  RadioButton,
  ToggleButton,
} from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Delivery } from '@adobe-commerce/elsie/icons';
import {
  classes,
  Slot,
  SlotProps,
  VComponent,
} from '@adobe-commerce/elsie/lib';
import { FunctionComponent, VNode } from 'preact';
import { HTMLAttributes } from 'preact/compat';
import { useEffect, useMemo, useRef } from 'preact/hooks';
import { ShippingMethodItemContext } from '@/checkout/containers/ShippingMethods';

/** Slot function type for ShippingMethodItem - uses Elsie Slot context for full replacement */
export type ShippingMethodItemSlot = SlotProps<ShippingMethodItemContext>;

/** Props for the ShippingMethodItem sub-component */
interface ShippingMethodItemProps {
  method: ShippingMethod;
  isSelected: boolean;
  busy: boolean;
  UIComponentType: UIComponentType;
  onSelectionChange: (method: ShippingMethod) => void;
  slot?: ShippingMethodItemSlot;
}

/**
 * Renders a single shipping method item wrapped in an Elsie Slot.
 * Merchants can use the slot with ctx.replaceWith() for complete UI replacement.
 */
const ShippingMethodItem: FunctionComponent<ShippingMethodItemProps> = ({
  method,
  isSelected,
  busy,
  UIComponentType,
  onSelectionChange,
  slot,
}) => {
  const context = useMemo(
    () => ({
      method,
      isSelected,
      busy,
      onSelect: () => onSelectionChange(method),
    }),
    [method, isSelected, busy, onSelectionChange]
  );

  const commonProps = {
    busy,
    className: 'checkout-shipping-methods__method',
    name: 'shipping-method',
    value: method.value,
    onChange: () => onSelectionChange(method),
  };

  const renderRadioButton = () => (
    <RadioButton
      {...commonProps}
      checked={isSelected}
      data-testid="shipping-method-radioButton"
      description={method.title}
      disabled={busy}
      id={method.value}
      label={
        <>
          {method.originalAmount && (
            <Price
              amount={method.originalAmount.value}
              className="checkout-shipping-methods__price--original"
              currency={method.originalAmount.currency}
              data-testid="shipping-method-original-price"
              variant="strikethrough"
            />
          )}
          <Price
            amount={method.amount.value}
            className="checkout-shipping-methods__price"
            currency={method.amount.currency}
          />
          &nbsp;
          <span>{method.carrier.title}</span>
        </>
      }
    />
  );

  const renderToggleButton = () => (
    <ToggleButton
      {...commonProps}
      data-testid="shipping-method-toggleButton"
      label={
        <>
          <span>{method.carrier.title}</span>
          <div className="checkout-shipping-methods__price-wrapper">
            {method.originalAmount && (
              <Price
                amount={method.originalAmount.value}
                className="checkout-shipping-methods__price--original"
                currency={method.originalAmount.currency}
                data-testid="shipping-method-original-price"
                variant="strikethrough"
              />
            )}
            <Price
              amount={method.amount.value}
              className="checkout-shipping-methods__price"
              currency={method.amount.currency}
            />
          </div>
        </>
      }
      selected={isSelected}
    />
  );

  const defaultUI =
    UIComponentType === 'RadioButton'
      ? renderRadioButton()
      : renderToggleButton();

  return (
    <Slot<ShippingMethodItemContext>
      context={context}
      name={`checkout-shipping-method-item-${method.value}`}
      slot={slot}
    >
      {defaultUI}
    </Slot>
  );
};

export interface ShippingMethodsProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  UIComponentType?: UIComponentType;
  busy?: boolean;
  error?: string | null;
  onDismissError?: () => void;
  onSelectionChange?: (method: ShippingMethod) => void;
  options: ShippingMethod[];
  selection: ShippingMethod | null;
  shippingMethodItemSlot?: ShippingMethodItemSlot;
  title?: VNode;
}

const ShippingMethodsComponent: FunctionComponent<ShippingMethodsProps> = ({
  className,
  busy = false,
  onSelectionChange = () => {},
  options,
  selection,
  shippingMethodItemSlot,
  title,
  UIComponentType = 'RadioButton',
  error = null,
  onDismissError = () => {},
  ...props
}) => {
  const translations = useText({
    EmptyState: 'Checkout.ShippingMethods.emptyState',
  });

  const hasError = error !== null;
  const errorRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (hasError && errorRef.current) {
      scrollToElement(errorRef.current);
    }
  }, [hasError]);

  return (
    <div
      {...props}
      className={classes(['checkout-shipping-methods', className])}
      data-testid="checkout-shipping-methods"
    >
      {title && (
        <VComponent className="checkout-shipping-methods__title" node={title} />
      )}

      <div className={classes(['checkout-shipping-methods__content'])}>
        <div
          className={classes([
            'checkout-shipping-methods__options',
            ['checkout-shipping-methods__options--busy', busy],
            [
              'checkout-shipping-methods__options--toggleButton',
              UIComponentType === 'ToggleButton',
            ],
          ])}
          data-testid="checkout-shipping-methods-options"
        >
          {options.length === 0 ? (
            <IllustratedMessage
              data-testid="checkout-shipping-methods-empty"
              icon={<Icon source={Delivery} />}
              message={<p>{translations.EmptyState}</p>}
            />
          ) : (
            options.map((method: ShippingMethod) => (
              <ShippingMethodItem
                key={method.value}
                UIComponentType={UIComponentType}
                busy={busy}
                isSelected={selection?.value === method.value}
                method={method}
                slot={shippingMethodItemSlot}
                onSelectionChange={onSelectionChange}
              />
            ))
          )}
        </div>
      </div>

      {hasError && (
        <div
          ref={errorRef}
          className="checkout-shipping-methods__error"
          data-testid="checkout-shipping-methods-alert"
        >
          <InLineAlert
            heading={error}
            type="error"
            variant="primary"
            onDismiss={onDismissError}
          />
        </div>
      )}
    </div>
  );
};

export const ShippingMethods = WithConditionals(
  ShippingMethodsComponent,
  ShippingMethodsSkeleton
);
