import { WithConditionals } from '@/checkout/components';
import '@/checkout/components/TermsAndConditions/TermsAndConditions.css';
import { TermsAndConditionsSkeleton } from '@/checkout/components/TermsAndConditions/TermsAndConditionsSkeleton';
import { classes, VComponent } from '@adobe-commerce/elsie/lib';
import { FunctionComponent, VNode } from 'preact';
import { HTMLAttributes } from 'preact/compat';

export interface TermsAndConditionsProps
  extends HTMLAttributes<HTMLFormElement> {
  agreements?: VNode;
  error?: string;
}

const TermsAndConditionsComponent: FunctionComponent<
  TermsAndConditionsProps
> = ({ className, agreements, error, ...props }) => {
  return (
    <div
      className="checkout-terms-and-conditions"
      data-testid="checkout-terms-and-conditions"
    >
      <form
        {...props}
        noValidate
        className={classes(['checkout-terms-and-conditions__form', className])}
        data-testid="checkout-terms-and-conditions-form"
        name="checkout-terms-and-conditions__form"
      >
        {agreements && (
          <VComponent
            className={classes(['checkout-terms-and-conditions__agreements'])}
            data-testid="checkout-terms-and-conditions-agreements"
            node={agreements}
          />
        )}

        {error && (
          <div
            className="checkout-terms-and-conditions__error"
            data-testid="checkout-terms-and-conditions-error"
          >
            {error}
          </div>
        )}
      </form>
    </div>
  );
};

export const TermsAndConditions = WithConditionals(
  TermsAndConditionsComponent,
  TermsAndConditionsSkeleton
);
