import '@/checkout/components/OutOfStock/OutOfStock.css';
import { Item as CartItem } from '@/checkout/types/cart';
import { Card, Icon, Image } from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { OrderError } from '@adobe-commerce/elsie/icons';
import { classes } from '@adobe-commerce/elsie/lib';
import { FunctionComponent } from 'preact';
import { HTMLAttributes } from 'preact/compat';

export interface OutOfStockProps extends HTMLAttributes<HTMLDivElement> {
  items: CartItem[];
  onRemoveOutOfStock?: (event: Event) => void;
  routeCart?: string;
}

export const OutOfStock: FunctionComponent<OutOfStockProps> = ({
  className,
  items,
  onRemoveOutOfStock,
  routeCart,
  ...props
}) => {
  const translations = useText({
    title: 'Checkout.OutOfStock.title',
    message: 'Checkout.OutOfStock.message',
    reviewCart: 'Checkout.OutOfStock.actions.reviewCart',
    removeOutOfStock: 'Checkout.OutOfStock.actions.removeOutOfStock',
  });

  return (
    <Card
      className={classes(['checkout-out-of-stock', className])}
      data-testid="checkout-out-of-stock"
      variant="secondary"
      {...props}
    >
      <h4 className="checkout-out-of-stock__title">
        <Icon size="16" source={OrderError} stroke="1" />
        {translations.title}
      </h4>

      <p className="checkout-out-of-stock__message">{translations.message}</p>

      <ol className="checkout-out-of-stock__items">
        {items.map((item) => (
          <li
            key={item.sku}
            className="checkout-out-of-stock__item"
            data-testid="out-of-stock-item"
          >
            <Image
              alt={item.image.alt}
              height="100"
              loading="eager"
              params={{ width: 100 }}
              src={item.image.src}
              width="100"
            />
          </li>
        ))}
      </ol>

      <div className="checkout-out-of-stock__actions">
        {routeCart && (
          <a
            className="checkout-out-of-stock__action"
            data-testid="review-cart"
            href={routeCart}
          >
            {translations.reviewCart}
          </a>
        )}

        {onRemoveOutOfStock && (
          <button
            className="checkout-out-of-stock__action"
            data-testid="remove-out-of-stock"
            type="button"
            onClick={onRemoveOutOfStock}
          >
            {translations.removeOutOfStock}
          </button>
        )}
      </div>
    </Card>
  );
};
