import { WithConditionals } from '@/checkout/components/ConditionalWrapper/ConditionalWrapper';
import '@/checkout/components/PaymentMethods/PaymentMethods.css';
import { PaymentMethodsSkeleton } from '@/checkout/components/PaymentMethods/PaymentMethodsSkeleton';
import { PaymentMethodConfig } from '@/checkout/containers';
import { PaymentMethod } from '@/checkout/data/models/payment-method';
import { scrollToElement } from '@/checkout/lib/utils/dom';
import { UIComponentType } from '@/checkout/types';
import {
  Icon,
  IllustratedMessage,
  InLineAlert,
  RadioButton,
  ToggleButton,
} from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { Wallet } from '@adobe-commerce/elsie/icons';
import { classes, VComponent } from '@adobe-commerce/elsie/lib';
import { FunctionComponent, VNode } from 'preact';
import { HTMLAttributes, useEffect, useRef } from 'preact/compat';

interface ExtendedPaymentMethod extends PaymentMethodConfig, PaymentMethod {}

export interface PaymentMethodsProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  error?: string | null;
  busy?: boolean;
  onDismissError?: () => void;
  onSelectionChange?: (value: PaymentMethod) => void;
  options?: ExtendedPaymentMethod[];
  paymentMethodContent?: VNode;
  selection: PaymentMethod | null;
  title?: VNode;
  UIComponentType?: UIComponentType;
}

interface PaymentOptionProps {
  UIComponentType?: UIComponentType;
  busy?: boolean;
  code: string;
  icon?: string;
  onSelectionChange: (value: PaymentMethod) => void;
  selected: boolean;
  title: string;
}

const PaymentOption: FunctionComponent<PaymentOptionProps> = ({
  UIComponentType = 'ToggleButton',
  busy,
  code,
  icon,
  onSelectionChange,
  selected,
  title,
}) => {
  const commonProps = {
    busy,
    className: 'checkout-payment-methods__method',
    label: title,
    name: 'payment-method',
    onChange: () => onSelectionChange({ code, title }),
    value: code,
  };

  return UIComponentType === 'ToggleButton' ? (
    <ToggleButton
      {...commonProps}
      // @ts-ignore
      icon={icon ? <Icon source={icon} /> : undefined}
      selected={selected}
    />
  ) : (
    <RadioButton {...commonProps} checked={selected} icon={icon ?? undefined} />
  );
};

const PaymentMethodsComponent: FunctionComponent<PaymentMethodsProps> = ({
  className,
  error = null,
  busy = false,
  onDismissError,
  onSelectionChange = () => {},
  options,
  paymentMethodContent,
  selection,
  title,
  UIComponentType,
}) => {
  const translations = useText({
    EmptyState: 'Checkout.PaymentMethods.emptyState',
  });

  const hasError = error !== null;
  const errorRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (hasError && errorRef.current) {
      scrollToElement(errorRef.current);
    }
  }, [hasError]);

  return (
    <div
      className={classes(['checkout-payment-methods', className])}
      data-testid="checkout-payment-methods"
    >
      {title && (
        <VComponent className="checkout-payment-methods__title" node={title} />
      )}

      {!busy && options!.length === 0 && (
        <IllustratedMessage
          data-testid="checkout-payment-methods-empty"
          icon={<Icon source={Wallet} />}
          message={<p>{translations.EmptyState}</p>}
        />
      )}

      <div
        className={classes([
          'checkout-payment-methods__wrapper',
          ['checkout-payment-methods__wrapper--busy', busy],
        ])}
        data-testid="checkout-payment-methods-wrapper"
      >
        <div
          className={classes([
            'checkout-payment-methods__methods',
            ['checkout-payment-methods--full-width', options!.length % 2 !== 0],
          ])}
        >
          {options?.map((method) => (
            <PaymentOption
              key={method.code}
              UIComponentType={UIComponentType}
              busy={busy}
              code={method.code}
              icon={method.icon}
              selected={selection?.code === method.code}
              title={method.displayLabel ?? true ? method.title : ''}
              onSelectionChange={onSelectionChange}
            />
          ))}
        </div>

        {paymentMethodContent && (
          <div className="checkout-payment-methods__content">
            {paymentMethodContent}
          </div>
        )}
      </div>

      {hasError && (
        <div
          ref={errorRef}
          className="checkout-payment-methods__error"
          data-testid="checkout-payment-methods-alert"
        >
          <InLineAlert
            heading={error}
            type="error"
            variant="primary"
            onDismiss={onDismissError}
          />
        </div>
      )}
    </div>
  );
};

export const PaymentMethods = WithConditionals(
  PaymentMethodsComponent,
  PaymentMethodsSkeleton
);
