import '@/checkout/components/BillToShippingAddress/BillToShippingAddress.css';
import { BillToShippingAddressSkeleton } from '@/checkout/components/BillToShippingAddress/BillToShippingAddressSkeleton';
import { WithConditionals } from '@/checkout/components/ConditionalWrapper/ConditionalWrapper';
import { Checkbox, InLineAlert } from '@adobe-commerce/elsie/components';
import { useText } from '@adobe-commerce/elsie/i18n';
import { classes } from '@adobe-commerce/elsie/lib/classes';
import { FunctionComponent } from 'preact';
import { ChangeEvent, HTMLAttributes } from 'preact/compat';

export interface BillToShippingAddressProps
  extends Omit<
    HTMLAttributes<HTMLInputElement>,
    'loading' | 'disabled' | 'onChange'
  > {
  disabled?: boolean;
  error?: string | null;
  onChange?: (checked: boolean) => void;
  onDismissError?: () => void;
}

const BillToShippingAddressComponent: FunctionComponent<
  BillToShippingAddressProps
> = ({
  className,
  checked,
  disabled,
  error = null,
  onChange = () => {},
  onDismissError = () => {},
}) => {
  const translations = useText({
    title: 'Checkout.BillToShippingAddress.title',
  });

  const hasError = error !== null;

  const handleChange = (event: Event | ChangeEvent<HTMLInputElement>) => {
    const checkbox = event.target as HTMLInputElement;
    onChange?.(checkbox.checked);
  };

  return (
    <div className="checkout-bill-to-shipping-address">
      <Checkbox
        checked={checked}
        className={classes([
          'checkout-bill-to-shipping-address__checkbox',
          className,
        ])}
        data-testid="bill-to-shipping-checkbox"
        disabled={disabled}
        label={translations.title}
        name="checkout-bill-to-shipping-address__checkbox"
        onChange={handleChange}
      />

      {hasError && (
        <div
          className="checkout-bill-to-shipping-address__error"
          data-testid="checkout-bill-to-shipping-address-alert"
        >
          <InLineAlert
            heading={error}
            type="error"
            variant="primary"
            onDismiss={onDismissError}
          />
        </div>
      )}
    </div>
  );
};

export const BillToShippingAddress = WithConditionals(
  BillToShippingAddressComponent,
  BillToShippingAddressSkeleton
);
